const phoneFromSender = $('Webhook').first().json.body.sender?.phone_number;                                                                                                                          

  let phone;                                                                                                                                                                                            

  if (phoneFromSender && phoneFromSender.startsWith('+')) {                                                                                                                                             
    phone = phoneFromSender;
  } else {
    const raw = String(
      $('Webhook').first().json.body.conversation.contact_inbox.source_id
    ).replace(/\D/g, '');                                                                                                                                                                               

    if (raw.startsWith('55')) {                                                                                                                                                                         
      phone = '+' + raw;
    } else {
      phone = '+55' + raw;
    }                                                                                                                                                                                                   
  }

  let phone_alt = phone;
  if (phone.startsWith('+55') && phone.length === 14) {
    const ddd = phone.slice(3, 5);
    const rest = phone.slice(6);
    phone_alt = '+55' + ddd + rest;                                                                                                                                                                     
  } else if (phone.startsWith('+55') && phone.length === 13) {
    const ddd = phone.slice(3, 5);                                                                                                                                                                      
    const rest = phone.slice(5);
    phone_alt = '+55' + ddd + '9' + rest;                                                                                                                                                               
  }

  return [{ json: { phone_normalized: phone, phone_alt: phone_alt } }];
